CREATE OR REPLACE FUNCTION calc_evidence_items_relative_path(p_evidence_item_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT(calc_evidence_items_parent_path(p_evidence_item_id), '/evidence/', (SELECT NULLIF(evidence_item_id, '') FROM evidence_items WHERE evidence_item_id = p_evidence_item_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_evidence_items_z_stat
-- Field: EvidenceItems.ZStat
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_evidence_items_z_stat(p_evidence_item_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN ((SELECT standard_error FROM evidence_items WHERE evidence_item_id = p_evidence_item_id))::NUMERIC > 0 THEN ((COALESCE(CASE WHEN ((SELECT effect_size FROM evidence_items WHERE evidence_item_id = p_evidence_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT effect_size FROM evidence_items WHERE evidence_item_id = p_evidence_item_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN ((SELECT standard_error FROM evidence_items WHERE evidence_item_id = p_evidence_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT standard_error FROM evidence_items WHERE evidence_item_id = p_evidence_item_id))::numeric ELSE NULL END, 0), 0)))::text ELSE (0)::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_evidence_items_is_confound_controlled
-- Field: EvidenceItems.IsConfoundControlled
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_evidence_items_is_confound_controlled(p_evidence_item_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN (COALESCE((SELECT is_adjusted_for_ancestry_pcs FROM evidence_items WHERE evidence_item_id = p_evidence_item_id), FALSE) AND COALESCE((SELECT is_adjusted_for_batch FROM evidence_items WHERE evidence_item_id = p_evidence_item_id), FALSE)) THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_evidence_items_is_qualified_evidence
-- Field: EvidenceItems.IsQualifiedEvidence
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_evidence_items_is_qualified_evidence(p_evidence_item_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN (calc_evidence_items_assay_is_high_quality(p_evidence_item_id) AND NOT (COALESCE((SELECT is_negative_control_arm FROM evidence_items WHERE evidence_item_id = p_evidence_item_id), FALSE)) AND (calc_evidence_items_z_stat(p_evidence_item_id))::NUMERIC >= 2 AND calc_evidence_items_is_confound_controlled(p_evidence_item_id)) THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

