  SELECT (CASE WHEN (SELECT NULLIF(status, '') FROM leopold_loops WHERE leopold_loop_id = p_leopold_loop_id) = 'done' THEN FALSE ELSE TRUE END)::boolean;
$$ LANGUAGE sql STABLE;

